+// Smoothly update character position towards target
+export function updateCharacterPosition(id: string, currentX: number, currentY: number, targetX: number, targetY: number, dt: number) {
+  const speed = 0.005; // Adjust speed for smoothness
+  const dx = targetX - currentX;
+  const dy = targetY - currentY;
+  const dist = Math.sqrt(dx * dx + dy * dy);
+  if (dist < 0.5) {
+    return { x: targetX, y: targetY };
+  }
+  const moveX = dx * speed * dt;
+  const moveY = dy * speed * dt;
+  return {
+    x: currentX + moveX,
+    y: currentY + moveY,
+  };
+}
+
+// Store character state positions for smooth movement
+const characterStates: Map<string, { x: number; y: number }> = new Map();
+
+export function getCS(id: string, defaultX: number, defaultY: number) {
+  if (!characterStates.has(id)) {
+    characterStates.set(id, { x: defaultX, y: defaultY });
+  }
+  return characterStates.get(id)!;
+}
+
+// Return workstation position for given tier (normalized 0-1 coords)
+export function getWorkstationPosition(tier: string) {
+  // Define workstation positions per tier (example values)
+  switch (tier) {
+    case 'king':
+      return { x: 0.5, y: 0.3 };
+    case 'nobility':
+      return { x: 0.6, y: 0.35 };
+    case 'knight':
+      return { x: 0.55, y: 0.4 };
+    case 'squire':
+      return { x: 0.5, y: 0.45 };
+    case 'healer':
+      return { x: 0.45, y: 0.5 };
+    case 'sentinel':
+      return { x: 0.6, y: 0.5 };
+    case 'scribe':
+      return { x: 0.55, y: 0.55 };
+    case 'judge':
+      return { x: 0.5, y: 0.6 };
+    case 'blacksmith':
+      return { x: 0.6, y: 0.65 };
+    default:
+      return { x: 0.5, y: 0.5 };
+  }
+}
