+const DEFAULT_AGENTS: AgentInfo[] = [
+  { id: '1', name: 'The Crown',      tier: 'king',       state: 'idle', currentJob: null },
+  { id: '2', name: 'Lord Regent',    tier: 'nobility',   state: 'idle', currentJob: null },
+  { id: '3', name: 'Sir Galahad',    tier: 'knight',     state: 'idle', currentJob: null },
+  { id: '4', name: 'Page Turner',    tier: 'squire',     state: 'idle', currentJob: null },
+  { id: '5', name: 'Brother Aldric', tier: 'healer',     state: 'idle', currentJob: null },
+  { id: '6', name: 'Night Watch',    tier: 'sentinel',   state: 'idle', currentJob: null },
+  { id: '7', name: 'Chronicler',     tier: 'scribe',     state: 'idle', currentJob: null },
+  { id: '8', name: 'Lord Justice',   tier: 'judge',      state: 'idle', currentJob: null },
+  { id: '9', name: 'Iron Forge',     tier: 'blacksmith', state: 'idle', currentJob: null },
+];
+
+export function AgentsScene() {
+  const canvasRef = useRef<HTMLCanvasElement>(null);
+  const [agents, setAgents] = useState<AgentInfo[]>(DEFAULT_AGENTS);
+
+  // Poll agents every 5 seconds
+  useEffect(() => {
+    let active = true;
+    const poll = () => {
+      fetch('/api/agents')
+        .then((r) => r.ok ? r.json() : [])
+        .then((data: AgentInfo[]) => {
+          if (active && Array.isArray(data) && data.length > 0) setAgents(data);
+        })
+        .catch(() => {});
+    };
+    poll();
+    const iv = setInterval(poll, 5000);
+    return () => {
+      active = false;
+      clearInterval(iv);
+    };
+  }, []);
+
+  useEffect(() => {
+    if (!canvasRef.current) return;
+
+    const cancel = startGameLoop((dt, frameCount) => {
+      const rc = syncCanvasSize(canvasRef.current!);
+      clearCanvas(rc);
+
+      const cols = 3;
+      const padding = 10;
+      const labelH = 24;
+      const roomW = Math.floor((rc.width - padding * (cols + 1)) / cols);
+      const roomH = Math.min(Math.floor(roomW * 0.7), 180);
+
+      // Group agents by tier
+      const agentsByTier = new Map<string, AgentInfo[]>();
+      for (const a of agents) {
+        const list = agentsByTier.get(a.tier) ?? [];
+        list.push(a);
+        agentsByTier.set(a.tier, list);
+      }
+
+      for (const slot of ROOM_GRID) {
+        const rx = padding + slot.col * (roomW + padding);
+        const ry = padding + slot.row * (roomH + labelH + padding + 6);
+
+        // Room label with shadow
+        drawText(rc, slot.label.toUpperCase(), rx + 5, ry + 15, 11, '#000000');
+        drawText(rc, slot.label.toUpperCase(), rx + 4, ry + 14, 11, COLORS.gold);
+
+        // Room background
+        drawRoom(rc.ctx, slot.tier, rx, ry + labelH, roomW, roomH, frameCount);
+
+        // Room border (double line for depth)
+        rc.ctx.strokeStyle = '#2a2030';
+        rc.ctx.lineWidth = 2;
+        rc.ctx.strokeRect(rx, ry + labelH, roomW, roomH);
+        rc.ctx.strokeStyle = '#5a5a6a';
+        rc.ctx.lineWidth = 1;
+        rc.ctx.strokeRect(rx + 1, ry + labelH + 1, roomW - 2, roomH - 2);
+
+        // Draw agents in this room (cap visible at 4, show overflow badge)
+        const tierAgents = agentsByTier.get(slot.tier) ?? [];
+        const maxVisible = 4;
+        const visible = tierAgents.slice(0, maxVisible);
+        const overflow = tierAgents.length - visible.length;
+        const charScale = Math.min(2.5, roomW / 90);
+
+        visible.forEach((agent, i) => {
+          // Determine target position based on agent state
+          let targetX: number;
+          let targetY: number;
+
+          if (agent.state === 'running') {
+            // Position at workstation furniture
+            const wsPos = getWorkstationPosition(slot.tier);
+            targetX = rx + roomW * wsPos.x;
+            targetY = ry + labelH + roomH * wsPos.y;
+          } else {
+            // Idle: random spread within walkable area
+            const spreadX = roomW * 0.7;
+            const spreadY = roomH * 0.45;
+            targetX = rx + roomW * 0.15 + i * Math.min(55, spreadX / Math.max(1, visible.length));
+            targetY = ry + labelH + roomH * 0.45;
+          }
+
+          // Get current character state and smoothly update position
+          const cs = getCS(agent.id, targetX, targetY);
+
+          // Smoothly update position towards target
+          const updatedPos = updateCharacterPosition(agent.id, cs.x, cs.y, targetX, targetY, dt);
+          cs.x = updatedPos.x;
+          cs.y = updatedPos.y;
+
+          // Draw character with updated position and pass state
+          drawCharacter(
+            rc.ctx,
+            slot.tier as CharacterType,
+            agent.state as AnimState,
+            cs.x,
+            cs.y,
+            charScale,
+            frameCount,
+            agent.id,
+            agent.currentJob,
+          );
+
+          // Name plate (below character)
+          const nameY = cs.y + 24 * charScale;
+          drawText(rc, agent.name, cs.x - 4, nameY, 9, COLORS.text);
         });
+      }
+
+      // TODO: draw overflow badge if overflow > 0
+    });
+
+    return () => cancel();
+  }, [agents]);
+
+  return <canvas ref={canvasRef} className="agents-scene" />;
+}
